"use client";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type FormEvent,
} from "react";
import { useRouter } from "next/navigation";
import type { ConfirmationResult } from "firebase/auth";
import {
  signIn,
  signUp,
  signOutUser,
  createRecaptchaVerifier,
  sendPhoneCode,
  confirmPhoneCode,
  sendPasswordReset,
  subscribeToAuthState,
} from "@/app/lib/firebase/auth";
import {
  upsertUserDoc,
  checkAdminAccess,
  setAuthCookie,
  clearAuthCookie,
  getAuthErrorMessage,
} from "./lib/adminAuth";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type AuthStep =
  | "welcome"
  | "login-chooser"
  | "email-signup"
  | "email-login"
  | "phone-entry"
  | "phone-otp"
  | "forgot-password"
  | "reset-sent"
  | "checking-access"
  | "access-denied";

// ---------------------------------------------------------------------------
// Icons (inline SVG for zero dependencies)
// ---------------------------------------------------------------------------

