// ---------------------------------------------------------------------------
// Shared UI primitives
// ---------------------------------------------------------------------------

function BackButton({ onClick }: { onClick: () => void }) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="mb-6 flex h-10 w-10 items-center justify-center rounded-full border border-zinc-200 text-zinc-600 transition-colors hover:bg-zinc-100 dark:border-zinc-700 dark:text-zinc-300 dark:hover:bg-zinc-800"
      aria-label="Go back"
    >
      <ArrowLeftIcon />
    </button>
  );
}

function AuthInput({
  id,
  type = "text",
  placeholder,
  value,
  onChange,
  autoComplete,
  autoFocus,
  disabled,
}: {
  id: string;
  type?: string;
  placeholder: string;
  value: string;
  onChange: (v: string) => void;
  autoComplete?: string;
  autoFocus?: boolean;
  disabled?: boolean;
}) {
  return (
    <input
      id={id}
      type={type}
      placeholder={placeholder}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      autoComplete={autoComplete}
      autoFocus={autoFocus}
      disabled={disabled}
      className="h-12 w-full border-b-2 border-zinc-200 bg-transparent text-base text-foreground placeholder:text-zinc-400 outline-none transition-colors focus:border-primary disabled:opacity-50 dark:border-zinc-700 dark:placeholder:text-zinc-500 dark:focus:border-zinc-400"
    />
  );
}

function PrimaryButton({
  children,
  type = "button",
  onClick,
  disabled,
}: {
  children: React.ReactNode;
  type?: "button" | "submit";
  onClick?: () => void;
  disabled?: boolean;
}) {
  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      className="flex h-12 w-full items-center justify-center rounded-xl bg-primary text-base font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
    >
      {children}
    </button>
  );
}

function MethodButton({
  icon,
  label,
  onClick,
}: {
  icon: React.ReactNode;
  label: string;
  onClick: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="flex h-[52px] w-full items-center gap-4 rounded-xl border border-zinc-200 bg-white px-5 text-base font-medium text-foreground transition-colors hover:bg-zinc-50 dark:border-zinc-700 dark:bg-zinc-900 dark:hover:bg-zinc-800"
    >
      <span className="flex-shrink-0">{icon}</span>
      <span className="flex-1 text-center pr-[22px]">{label}</span>
    </button>
  );
}

function ErrorMessage({ message }: { message: string | null }) {
  if (!message) return null;
  return (
    <p className="text-sm text-red-600 dark:text-red-400" role="alert">
      {message}
    </p>
  );
}

// ---------------------------------------------------------------------------
// Main funnel component
// ---------------------------------------------------------------------------

export function AdminAuthFunnel() {
  const router = useRouter();

  // Step state
  const [step, setStep] = useState<AuthStep>("welcome");
  const [mode, setMode] = useState<"signup" | "login">("signup");

  // Form state
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [phone, setPhone] = useState("");
  const [otp, setOtp] = useState("");

  // Async state
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Phone auth refs
  const confirmationRef = useRef<ConfirmationResult | null>(null);
  const recaptchaContainerRef = useRef<HTMLDivElement | null>(null);
  const recaptchaInitialized = useRef(false);

  // OTP resend cooldown
  const [resendCooldown, setResendCooldown] = useState(0);

  // Redirect already-authed users
  useEffect(() => {
    const unsubscribe = subscribeToAuthState(async (user) => {
      if (user && step === "welcome") {
        setStep("checking-access");
        await handlePostAuth(user);
      }
    });
    return unsubscribe;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Resend cooldown timer
  useEffect(() => {
    if (resendCooldown <= 0) return;
    const timer = setTimeout(() => setResendCooldown((c) => c - 1), 1000);
    return () => clearTimeout(timer);
  }, [resendCooldown]);

  // ------- Post-auth flow -------

  const handlePostAuth = useCallback(
    async (user: import("firebase/auth").User) => {
      setStep("checking-access");
      setError(null);
      try {
        await upsertUserDoc(user);
        const isAdmin = await checkAdminAccess(user.uid);
        if (isAdmin) {
          const token = await user.getIdToken();
          setAuthCookie(token);
          router.push("/admin");
        } else {
          setStep("access-denied");
        }
      } catch {
        setStep("access-denied");
      }
    },
    [router]
  );

  // ------- Navigation helpers -------

  function goTo(next: AuthStep) {
    setError(null);
    setStep(next);
  }

  function goWelcome() {
    setError(null);
    setPassword("");
    setConfirmPassword("");
    setOtp("");
    setStep("welcome");
  }

  // ------- Email sign up -------

  async function handleEmailSignUp(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!email.trim()) return setError("Please enter your email.");
    if (password.length < 6)
      return setError("Password must be at least 6 characters.");
    if (password !== confirmPassword)
      return setError("Passwords do not match.");

    setLoading(true);
    try {
      const { user } = await signUp(email, password);
      await handlePostAuth(user);
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Email sign in -------

  async function handleEmailSignIn(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!email.trim()) return setError("Please enter your email.");
    if (!password) return setError("Please enter your password.");

    setLoading(true);
    try {
      const { user } = await signIn(email, password);
      await handlePostAuth(user);
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Phone: send code -------

  async function handleSendPhoneCode(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!phone.trim()) return setError("Please enter your phone number.");

    setLoading(true);
    try {
      if (!recaptchaInitialized.current && recaptchaContainerRef.current) {
        createRecaptchaVerifier(recaptchaContainerRef.current, {
          size: "invisible",
        });
        recaptchaInitialized.current = true;
      }
      const confirmation = await sendPhoneCode(phone);
      confirmationRef.current = confirmation;
      setResendCooldown(60);
      goTo("phone-otp");
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Phone: verify OTP -------

  async function handleVerifyOtp(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (otp.length < 6) return setError("Please enter the 6-digit code.");
    if (!confirmationRef.current)
      return setError("Session expired. Please request a new code.");

    setLoading(true);
    try {
      const { user } = await confirmPhoneCode(confirmationRef.current, otp);
      await handlePostAuth(user);
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Phone: resend code -------

  async function handleResendCode() {
    if (resendCooldown > 0) return;
    setError(null);
    setLoading(true);
    try {
      recaptchaInitialized.current = false;
      if (recaptchaContainerRef.current) {
        createRecaptchaVerifier(recaptchaContainerRef.current, {
          size: "invisible",
        });
        recaptchaInitialized.current = true;
      }
      const confirmation = await sendPhoneCode(phone);
      confirmationRef.current = confirmation;
      setResendCooldown(60);
      setOtp("");
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Forgot password -------

  async function handleForgotPassword(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!email.trim()) return setError("Please enter your email.");

    setLoading(true);
    try {
      await sendPasswordReset(email);
      goTo("reset-sent");
    } catch (err) {
      setError(getAuthErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  // ------- Access denied: sign out -------

  async function handleSignOutAndReset() {
    clearAuthCookie();
    await signOutUser();
    setEmail("");
    setPassword("");
    setConfirmPassword("");
    setPhone("");
    setOtp("");
    goWelcome();
  }

  // =====================================================================
  // RENDER: each step
  // =====================================================================

  // -- Welcome (sign up entry point) --
  if (step === "welcome") {
    return (
      <Shell>
        {/* Logo space */}
        <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-primary/10 text-primary dark:bg-white/10 dark:text-white">
          <span className="text-2xl font-bold">D</span>
        </div>

        <h1 className="text-2xl font-bold tracking-tight">Dorm AI</h1>

        <p className="text-center text-base leading-relaxed text-secondary-alt dark:text-zinc-400">
          Streamline inspections, catch damages early, and manage your
          properties with ease.
        </p>

        <div className="flex w-full flex-col gap-3 pt-2">
          <MethodButton
            icon={<MailIcon className="text-foreground" />}
            label="Sign up with email"
            onClick={() => {
              setMode("signup");
              goTo("email-signup");
            }}
          />
          <MethodButton
            icon={<PhoneIcon className="text-foreground" />}
            label="Sign up with phone"
            onClick={() => {
              setMode("signup");
              goTo("phone-entry");
            }}
          />
        </div>

        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          Already have an account?{" "}
          <button
            type="button"
            onClick={() => {
              setMode("login");
              goTo("login-chooser");
            }}
            className="font-semibold text-foreground underline underline-offset-2"
          >
            Log in
          </button>
        </p>

        <Footer />
      </Shell>
    );
  }

  // -- Login chooser --
  if (step === "login-chooser") {
    return (
      <Shell>
        <BackButton onClick={goWelcome} />
        <h1 className="text-2xl font-bold tracking-tight">Welcome back</h1>

        <div className="flex w-full flex-col gap-3 pt-2">
          <MethodButton
            icon={<MailIcon className="text-foreground" />}
            label="Continue with email"
            onClick={() => goTo("email-login")}
          />
          <MethodButton
            icon={<PhoneIcon className="text-foreground" />}
            label="Continue with phone"
            onClick={() => goTo("phone-entry")}
          />
        </div>

        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          Don&apos;t have an account?{" "}
          <button
            type="button"
            onClick={() => {
              setMode("signup");
              goWelcome();
            }}
            className="font-semibold text-foreground underline underline-offset-2"
          >
            Create account
          </button>
        </p>
      </Shell>
    );
  }

  // -- Email sign up --
  if (step === "email-signup") {
    return (
      <Shell>
        <BackButton onClick={goWelcome} />
        <h1 className="text-2xl font-bold tracking-tight">
          Sign up with email:
        </h1>

        <form onSubmit={handleEmailSignUp} className="flex w-full flex-col gap-4">
          <AuthInput
            id="signup-email"
            type="email"
            placeholder="Email"
            value={email}
            onChange={setEmail}
            autoComplete="email"
            autoFocus
            disabled={loading}
          />
          <AuthInput
            id="signup-password"
            type="password"
            placeholder="Password"
            value={password}
            onChange={setPassword}
            autoComplete="new-password"
            disabled={loading}
          />
          <AuthInput
            id="signup-confirm"
            type="password"
            placeholder="Confirm password"
            value={confirmPassword}
            onChange={setConfirmPassword}
            autoComplete="new-password"
            disabled={loading}
          />
          <ErrorMessage message={error} />
          <PrimaryButton type="submit" disabled={loading}>
            {loading ? "Creating account…" : "Sign up"}
          </PrimaryButton>
        </form>

        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          Already have an account?{" "}
          <button
            type="button"
            onClick={() => goTo("login-chooser")}
            className="font-semibold text-foreground underline underline-offset-2"
          >
            Log in
          </button>
        </p>
      </Shell>
    );
  }

  // -- Email login --
  if (step === "email-login") {
    return (
      <Shell>
        <BackButton onClick={() => goTo("login-chooser")} />
        <h1 className="text-2xl font-bold tracking-tight">
          Continue with email:
        </h1>

        <form onSubmit={handleEmailSignIn} className="flex w-full flex-col gap-4">
          <AuthInput
            id="login-email"
            type="email"
            placeholder="Email"
            value={email}
            onChange={setEmail}
            autoComplete="email"
            autoFocus
            disabled={loading}
          />
          <AuthInput
            id="login-password"
            type="password"
            placeholder="Password"
            value={password}
            onChange={setPassword}
            autoComplete="current-password"
            disabled={loading}
          />
          <ErrorMessage message={error} />
          <PrimaryButton type="submit" disabled={loading}>
            {loading ? "Logging in…" : "Log in"}
          </PrimaryButton>
        </form>

        <button
          type="button"
          onClick={() => goTo("forgot-password")}
          className="text-sm font-semibold text-foreground"
        >
          Forgot password?
        </button>
      </Shell>
    );
  }

  // -- Phone entry --
  if (step === "phone-entry") {
    return (
      <Shell>
        <BackButton
          onClick={() =>
            goTo(mode === "login" ? "login-chooser" : "welcome")
          }
        />
        <h1 className="text-2xl font-bold tracking-tight">
          Continue with phone:
        </h1>
        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          We&apos;ll send a verification code to your number.
        </p>

        <form
          onSubmit={handleSendPhoneCode}
          className="flex w-full flex-col gap-4"
        >
          <AuthInput
            id="phone-number"
            type="tel"
            placeholder="+1 (555) 000-0000"
            value={phone}
            onChange={setPhone}
            autoComplete="tel"
            autoFocus
            disabled={loading}
          />
          <ErrorMessage message={error} />
          <PrimaryButton type="submit" disabled={loading}>
            {loading ? "Sending code…" : "Send code"}
          </PrimaryButton>
        </form>

        <div ref={recaptchaContainerRef} />
      </Shell>
    );
  }

  // -- Phone OTP --
  if (step === "phone-otp") {
    return (
      <Shell>
        <BackButton onClick={() => goTo("phone-entry")} />
        <h1 className="text-2xl font-bold tracking-tight">
          Enter verification code
        </h1>
        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          We sent a 6-digit code to <span className="font-medium text-foreground">{phone}</span>
        </p>

        <form
          onSubmit={handleVerifyOtp}
          className="flex w-full flex-col gap-4"
        >
          <AuthInput
            id="otp-code"
            type="text"
            placeholder="000000"
            value={otp}
            onChange={(v) => setOtp(v.replace(/\D/g, "").slice(0, 6))}
            autoComplete="one-time-code"
            autoFocus
            disabled={loading}
          />
          <ErrorMessage message={error} />
          <PrimaryButton type="submit" disabled={loading || otp.length < 6}>
            {loading ? "Verifying…" : "Verify"}
          </PrimaryButton>
        </form>

        <button
          type="button"
          onClick={handleResendCode}
          disabled={resendCooldown > 0 || loading}
          className="text-sm font-medium text-zinc-500 disabled:opacity-50 dark:text-zinc-400"
        >
          {resendCooldown > 0
            ? `Resend code in ${resendCooldown}s`
            : "Resend code"}
        </button>

        <div ref={recaptchaContainerRef} />
      </Shell>
    );
  }

  // -- Forgot password --
  if (step === "forgot-password") {
    return (
      <Shell>
        <BackButton onClick={() => goTo("email-login")} />
        <h1 className="text-2xl font-bold tracking-tight">Reset password</h1>
        <p className="text-sm text-zinc-500 dark:text-zinc-400">
          We&apos;ll confirm your account by sending a link to the email address
          below.
        </p>

        <form
          onSubmit={handleForgotPassword}
          className="flex w-full flex-col gap-4"
        >
          <AuthInput
            id="reset-email"
            type="email"
            placeholder="Email"
            value={email}
            onChange={setEmail}
            autoComplete="email"
            autoFocus
            disabled={loading}
          />
          <ErrorMessage message={error} />
          <PrimaryButton type="submit" disabled={loading}>
            {loading ? "Sending…" : "Send link"}
          </PrimaryButton>
        </form>
      </Shell>
    );
  }

  // -- Reset sent --
  if (step === "reset-sent") {
    return (
      <Shell>
        <h1 className="text-2xl font-bold tracking-tight">
          Check your email
        </h1>
        <p className="text-center text-sm text-zinc-500 dark:text-zinc-400">
          We sent a password reset link to{" "}
          <span className="font-medium text-foreground">{email}</span>. Check
          your inbox and follow the link to reset your password.
        </p>
        <PrimaryButton onClick={() => goTo("email-login")}>
          Back to log in
        </PrimaryButton>
      </Shell>
    );
  }

  // -- Checking access (loading) --
  if (step === "checking-access") {
    return (
      <Shell>
        <div className="flex flex-col items-center gap-4 py-8">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-zinc-200 border-t-primary dark:border-zinc-700 dark:border-t-white" />
          <p className="text-sm text-zinc-500 dark:text-zinc-400">
            Verifying access…
          </p>
        </div>
      </Shell>
    );
  }

  // -- Access denied --
  if (step === "access-denied") {
    return (
      <Shell>
        <h1 className="text-2xl font-bold tracking-tight">Access denied</h1>
        <p className="text-center text-sm text-zinc-500 dark:text-zinc-400">
          Your account doesn&apos;t have admin access. Contact your
          administrator to get the ADMIN role assigned to your account.
        </p>
        <PrimaryButton onClick={handleSignOutAndReset}>
          Sign out
        </PrimaryButton>
      </Shell>
    );
  }

  return null;
}

// ---------------------------------------------------------------------------
// Layout shell
// ---------------------------------------------------------------------------

function Shell({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex min-h-[100dvh] items-center justify-center bg-white px-6 py-12 dark:bg-black">
      <div className="flex w-full max-w-[420px] flex-col items-start gap-5">
        {children}
      </div>
    </div>
  );
}

function Footer() {
  return (
    <p className="pt-4 text-center text-xs text-zinc-400 dark:text-zinc-500 w-full">
      By using Dorm AI, you agree to our{" "}
      <a href="/terms" className="underline underline-offset-2">
        Terms of Use
      </a>{" "}
      and{" "}
      <a href="/privacy" className="underline underline-offset-2">
        Privacy Policy
      </a>
      .
    </p>
  );
}
